export function initialize(sentinelElement, dotNetHelper) {
    const observer = new IntersectionObserver(entries => {
        for (const entry of entries) {
            if (entry.isIntersecting) {
                dotNetHelper.invokeMethodAsync('OnSentinelVisible');
            }
        }
    }, { rootMargin: '0px 0px 250px 0px' });

    observer.observe(sentinelElement);

    return { observer, sentinelElement };
}

export function dispose(instance) {
    if (instance) {
        instance.observer.unobserve(instance.sentinelElement);
        instance.observer.disconnect();
    }
}

@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container" style="overflow-y:auto; max-height:100%;">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="sentinelRef" class="infinite-scroll-sentinel"
             style="display:flex; justify-content:center; padding:1rem;">
            @if (isLoading)
            {
                <div class="spinner-border text-secondary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            }
        </div>
    }
</div>

@code {
    /// <summary>The collection of items to render.</summary>
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    /// <summary>Template for rendering each item.</summary>
    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    /// <summary>Whether additional items are available to load.</summary>
    [Parameter]
    public bool HasMore { get; set; }

    /// <summary>Callback invoked when more items should be loaded.</summary>
    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    private ElementReference sentinelRef;
    private IJSObjectReference? module;
    private IJSObjectReference? observerInstance;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? dotNetRef;
    private bool isLoading;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./js/infinite-scroll.js");
            await SetupObserver();
        }
    }

    public override async Task SetParametersAsync(ParameterView parameters)
    {
        var previousHasMore = HasMore;
        await base.SetParametersAsync(parameters);

        // Re-attach observer when HasMore transitions back to true
        if (!previousHasMore && HasMore && module is not null)
        {
            await SetupObserver();
        }
    }

    private async Task SetupObserver()
    {
        if (module is null || dotNetRef is null)
            return;

        // Dispose any previous observer before creating a new one
        if (observerInstance is not null)
        {
            await module.InvokeVoidAsync("dispose", observerInstance);
            observerInstance = null;
        }

        // Wait one render so the sentinel element is in the DOM
        await Task.Yield();
        StateHasChanged();
        await Task.Yield();

        if (HasMore)
        {
            observerInstance = await module.InvokeAsync<IJSObjectReference>(
                "initialize", sentinelRef, dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (isLoading || !HasMore)
            return;

        isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        isLoading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (module is not null)
        {
            if (observerInstance is not null)
            {
                await module.InvokeVoidAsync("dispose", observerInstance);
            }
            await module.DisposeAsync();
        }
        dotNetRef?.Dispose();
    }
}

